1	package adapter
2	
3	import (
4		"bytes"
5		"context"
6		"encoding/json"
7		"errors"
8		"fmt"
9		"path"
10		"regexp"
11		"strings"
12		"time"
13	
14		"github.com/agent-sync/agent-sync/internal/adapter/contract"
15	)
16	
17	// reWindowsVolumePrefix matches a leading drive letter ("C:", "d:", ...).
18	// Such a prefix is absolute on Windows when interpreted by OS path rules
19	// even though path.IsAbs (which uses POSIX rules) reports it as relative,
20	// so we reject it on every OS to keep declared-outputs gating safe
21	// regardless of host platform. Same shape used in
22	// manifest.ValidateReservedPrefix.
23	var reWindowsVolumePrefix = regexp.MustCompile(`\A[A-Za-z]:`)
24	
25	// Initialize sends the initialize request, validates the cookie echo
26	// and protocol version, and captures the adapter's declared_outputs +
27	// capabilities for later enforcement. After Initialize returns
28	// successfully, the session is ready for Initialized + Emit.
29	func (s *AdapterSession) Initialize(ctx context.Context) (*contract.InitializeResult, error) {
30		if s.state != sessionStateNew {
31			return nil, &RuntimeError{
32				Class: contract.ErrorClassAdapterProtocolOrder,
33				Err:   fmt.Errorf("%w: Initialize called from state %d", ErrAdapterProtocolOrderViolation, s.state),
34			}
35		}
36	
37		timeout := resolveTimeouts(s.options.Timeouts).Handshake
38		rctx, cancel := context.WithTimeout(ctx, timeout)
39		defer cancel()
40	
41		id := s.ids.Next()
42		s.ids.MarkPending(id, contract.MethodInitialize)
43	
44		params := contract.InitializeParams{
45			Client:           "agent-sync",
46			ProtocolVersions: []string{ContractVersionV1},
47			Cookie:           s.cookie,
48			WorkspaceRoot:    s.options.WorkspaceRoot,
49			ReservedPrefix:   s.adapter.Manifest.ReservedPrefix,
50			IRVersion:        s.options.IRVersion,
51		}
52	
53		resp, err := s.requestResponse(rctx, id, contract.MethodInitialize, params, contract.MethodInitialize, timeout)
54		if err != nil {
55			s.ids.Cancel(id)
56			return nil, err
57		}
58	
59		var result contract.InitializeResult
60		if err := json.Unmarshal(resp.Result, &result); err != nil {
61			return nil, &RuntimeError{
62				Class: contract.ErrorClassAdapterPanic,
63				Err:   fmt.Errorf("decode initialize result: %w", err),
64			}
65		}
66	
67		// Cookie validation: bundled adapters skip (they share process).
68		// Subprocess adapters MUST echo the cookie verbatim. The cookie
69		// itself never appears in the error message — leaking it would
70		// undermine the auth boundary it exists to enforce.
71		if s.adapter.Source != SourceBundled {
72			echoed := extractCookieFromResult(resp.Result)
73			if echoed == "" {
74				return nil, &RuntimeError{
75					Class: contract.ErrorClassAdapterExecDenied,
76					Err:   ErrAdapterCookieMissing,
77				}
78			}
79			if echoed != s.cookie {
80				return nil, &RuntimeError{
81					Class: contract.ErrorClassAdapterExecDenied,
82					Err:   ErrAdapterCookieMismatch,
83				}
84			}
85		}
86	
87		if result.ProtocolVersion != ContractVersionV1 {
88			return nil, &RuntimeError{
89				Class: contract.ErrorClassAdapterProtocolMismatch,
90				Err:   fmt.Errorf("%w: adapter speaks %q (want %q)", ErrAdapterProtocolMismatch, result.ProtocolVersion, ContractVersionV1),
91			}
92		}
93	
94		// Record which kinds were declared "supported" — used by
95		// capability-lied detection after Emit.
96		for kind, level := range result.Capabilities.ConceptKinds {
97			if level == contract.CapabilitySupported {
98				s.gateChecks[contract.OpKind(kind)] = true
99			}
100		}
101	
102		s.initResult = &result
103		s.state = sessionStateInitialized
104		return &result, nil
105	}
106	
107	// Initialized sends the initialized notification. After this returns,
108	// the session is ready for Emit. The notification has no response;
109	// any error here is purely the wire-level send failure.
110	func (s *AdapterSession) Initialized(ctx context.Context) error {
111		if s.state != sessionStateInitialized {
112			return &RuntimeError{
113				Class: contract.ErrorClassAdapterProtocolOrder,
114				Err:   fmt.Errorf("%w: Initialized called from state %d", ErrAdapterProtocolOrderViolation, s.state),
115			}
116		}
117		notification := contract.Notification{Method: contract.MethodInitialized}
118		payload, err := json.Marshal(notification)
119		if err != nil {
120			return &RuntimeError{
121				Class: contract.ErrorClassAdapterPanic,
122				Err:   fmt.Errorf("marshal initialized notification: %w", err),
123			}
124		}
125		if err := s.transport.Send(ctx, payload); err != nil {
126			return classifySendError(err)
127		}
128		return nil
129	}
130	
131	// Emit sends the emit request for one target with the given IR, then
132	// reads the streamed ops + final response. Each op is checked against
133	// the declared_outputs gate; any violation cancels the session.
134	//
135	// IR is supplied as json.RawMessage to keep this package decoupled
136	// from internal/ir.
137	func (s *AdapterSession) Emit(ctx context.Context, target string, ir json.RawMessage) (*contract.EmitResult, error) {
138		if s.state != sessionStateInitialized && s.state != sessionStateEmitting {
139			return nil, &RuntimeError{
140				Class: contract.ErrorClassAdapterProtocolOrder,
141				Err:   fmt.Errorf("%w: Emit called from state %d", ErrAdapterProtocolOrderViolation, s.state),
142			}
143		}
144		s.state = sessionStateEmitting
145	
146		timeout := resolveTimeouts(s.options.Timeouts).Emit
147		rctx, cancel := context.WithTimeout(ctx, timeout)
148		defer cancel()
149	
150		id := s.ids.Next()
151		s.ids.MarkPending(id, contract.MethodEmit)
152	
153		params := contract.EmitParams{
154			Target: target,
155			IR:     ir,
156		}
157	
158		resp, err := s.requestResponse(rctx, id, contract.MethodEmit, params, contract.MethodEmit, timeout)
159		if err != nil {
160			s.ids.Cancel(id)
161			return nil, err
162		}
163	
164		var result contract.EmitResult
165		if err := json.Unmarshal(resp.Result, &result); err != nil {
166			return nil, &RuntimeError{
167				Class: contract.ErrorClassAdapterPanic,
168				Err:   fmt.Errorf("decode emit result: %w", err),
169			}
170		}
171	
172		// Declared-outputs integrity gate. Each performed op must target a
173		// path inside one of the declared outputs. Warnings are exempt
174		// (concept-level, no path).
175		nonWarningOps := 0
176		for i, op := range result.OpsPerformed {
177			if op.Op == contract.OpKindWarning {
178				continue
179			}
180			nonWarningOps++
181			if !s.pathInDeclaredOutputs(op.Path) {
182				return nil, &RuntimeError{
183					Class: contract.ErrorClassAdapterUndeclaredOutput,
184					Err: fmt.Errorf("%w: op[%d] kind=%s path=%q",
185						ErrAdapterUndeclaredOutput, i, op.Op, op.Path),
186				}
187			}
188		}
189	
190		// Capability-lied detection: if the adapter declared any kind as
191		// "supported" in initialize and the IR contained nodes of those
192		// kinds *targeted at this adapter*, then the adapter must have
193		// emitted at least one non-warning op. An adapter that says "yes,
194		// I handle X" and then silently does nothing is a worse failure
195		// mode than a "won't handle X" honest decline — silent
196		// nullification breaks the determinism guarantee.
197		//
198		// The per-node `targets` filter matters: an IR node with
199		// `targets: [other-adapter]` is intentionally invisible to this
200		// adapter, so a zero-op response is correct (not a lie). Without
201		// this filter, mixed-target manifests fail at sync time even
202		// though every adapter behaves correctly.
203		if nonWarningOps == 0 && irContainsSupportedKindForTarget(ir, s.gateChecks, s.adapter.Manifest.Name) {
204			return nil, &RuntimeError{
205				Class: contract.ErrorClassAdapterCapabilityLied,
206				Err:   ErrAdapterCapabilityLied,
207			}
208		}
209	
210		return &result, nil
211	}
212	
213	// irContainsSupportedKindForTarget reports whether the IR has at
214	// least one node whose kind appears in the supported set AND whose
215	// per-node `targets` filter applies to the given adapter. A node
216	// with empty `targets` applies to every adapter (matches the IR v1
217	// spec); a node listing specific targets only applies if `target`
218	// appears in that list.
219	//
220	// Best-effort: a malformed IR returns false (no false positives —
221	// better to under-report than to flag a legitimate adapter for what
222	// is really a runtime bug).
223	//
224	// The IR is scanned with a streaming decoder so a large IR doesn't
225	// force a full unmarshal into memory. We walk the top-level object
226	// looking for a "nodes" array, then decode one element at a time
227	// into a small struct that captures only "kind" and "targets" —
228	// short-circuiting on the first supported, in-target match.
229	func irContainsSupportedKindForTarget(ir json.RawMessage, supported map[contract.OpKind]bool, target string) bool {
230		if len(supported) == 0 {
231			return false
232		}
233		dec := json.NewDecoder(bytes.NewReader(ir))
234	
235		// Expect the document to open with "{".
236		tok, err := dec.Token()
237		if err != nil {
238			return false
239		}
240		if d, ok := tok.(json.Delim); !ok || d != '{' {
241			return false
242		}
243	
244		// Walk top-level keys. For "nodes", drop into the array and scan
245		// elements one at a time. For everything else, skip the value.
246		for dec.More() {
247			keyTok, err := dec.Token()
248			if err != nil {
249				return false
250			}
251			key, ok := keyTok.(string)
252			if !ok {
253				return false
254			}
255			if key != "nodes" {
256				if err := skipJSONValue(dec); err != nil {
257					return false
258				}
259				continue
260			}
261			// Expect "[".
262			tok, err := dec.Token()
263			if err != nil {
264				return false
265			}
266			if d, ok := tok.(json.Delim); !ok || d != '[' {
267				return false
268			}
269			for dec.More() {
270				var node struct {
271					Kind    string   `json:"kind"`
272					Targets []string `json:"targets"`
273				}
274				if err := dec.Decode(&node); err != nil {
275					return false
276				}
277				if !supported[contract.OpKind(node.Kind)] {
278					continue
279				}
280				if nodeAppliesToTarget(node.Targets, target) {
281					return true
282				}
283			}
284			// Consume the closing "]". After "nodes" there's nothing else
285			// we need from the IR; done either way.
286			if _, err := dec.Token(); err != nil {
287				return false
288			}
289			return false
290		}
291		return false
292	}
293	
294	// nodeAppliesToTarget reports whether a node with the given Targets
295	// list applies to the supplied adapter target. Empty Targets means
296	// "all adapters" per the IR v1 spec.
297	func nodeAppliesToTarget(targets []string, target string) bool {
298		if len(targets) == 0 {
299			return true
300		}
301		for _, t := range targets {
302			if t == target {
303				return true
304			}
305		}
306		return false
307	}
308	
309	// skipJSONValue consumes the next JSON value from dec (object, array,
310	// or scalar) and discards it. Used to skip top-level fields that
311	// irContainsSupportedKind does not care about without buffering them.
312	func skipJSONValue(dec *json.Decoder) error {
313		tok, err := dec.Token()
314		if err != nil {
315			return err
316		}
317		d, ok := tok.(json.Delim)
318		if !ok {
319			// Scalar — already consumed.
320			return nil
321		}
322		if d != '{' && d != '[' {
323			return fmt.Errorf("unexpected delimiter %q", d)
324		}
325		depth := 1
326		for depth > 0 {
327			t, err := dec.Token()
328			if err != nil {
329				return err
330			}
331			if dd, ok := t.(json.Delim); ok {
332				switch dd {
333				case '{', '[':
334					depth++
335				case '}', ']':
336					depth--
337				}
338			}
339		}
340		return nil
341	}
342	
343	// Shutdown sends the shutdown request and tears down the transport.
344	// Returns the classified termination error (nil for clean exit).
345	//
346	// Shutdown is the terminal phase — after it returns, the session is
347	// finalized and no further methods may be called.
348	func (s *AdapterSession) Shutdown(ctx context.Context) error {
349		switch s.state {
350		case sessionStateClosed:
351			return nil
352		case sessionStateNew:
353			// Shutdown without Initialize: just tear down the transport.
354			s.state = sessionStateClosed
355			return s.transport.Close(ctx)
356		}
357	
358		timeout := resolveTimeouts(s.options.Timeouts).Shutdown
359		rctx, cancel := context.WithTimeout(ctx, timeout)
360		defer cancel()
361	
362		id := s.ids.Next()
363		s.ids.MarkPending(id, contract.MethodShutdown)
364	
365		params := contract.ShutdownParams{}
366		_, err := s.requestResponse(rctx, id, contract.MethodShutdown, params, contract.MethodShutdown, timeout)
367		if err != nil {
368			s.ids.Cancel(id)
369			// Don't return here; still tear down the transport so the
370			// process exits. Log the error via the closeErr.
371		} else {
372			// Protocol-level shutdown succeeded. Inform the transport so
373			// its Close path knows to treat any non-zero exit as expected.
374			// Without this signal, an adapter that returns from main with
375			// a non-zero status after responding to shutdown would surface
376			// as a SubprocessExitError, which would mis-classify a clean
377			// shutdown as a fault.
378			s.transport.MarkProtocolShutdownAcked()
379		}
380	
381		closeErr := s.transport.Close(ctx)
382	
383		// Any ids still pending here have been abandoned: the adapter
384		// returned an error or the transport was torn down before a
385		// response arrived. Failed requests are explicitly removed with
386		// Cancel(id), and any ids still pending at this point will be
387		// dropped with the IDCorrelator when this session is closed, so
388		// retention is bounded by session lifetime rather than by a
389		// max-pending eviction policy.
390	
391		s.state = sessionStateClosed
392	
393		if err != nil {
394			return err
395		}
396		if closeErr != nil {
397			return classifyTransportError(closeErr)
398		}
399		return nil
400	}
401	
402	// requestResponse sends a request, waits for the matching response,
403	// and returns it. Honors ctx for cancellation. Errors are wrapped in
404	// RuntimeError with the appropriate ErrorClass.
405	//
406	// phase identifies the lifecycle phase for error messages (initialize,
407	// emit, shutdown). phaseTimeout is the per-phase deadline so a timeout
408	// error reports the correct duration — without this, a 5s handshake
409	// timeout was being reported as "exceeded 30s" because the runtime
410	// always read its handshake timeout for the message.
411	func (s *AdapterSession) requestResponse(ctx context.Context, id contract.ID, method string, params interface{}, phase string, phaseTimeout time.Duration) (*contract.Message, error) {
412		paramsRaw, err := json.Marshal(params)
413		if err != nil {
414			return nil, &RuntimeError{
415				Class: contract.ErrorClassAdapterPanic,
416				Err:   fmt.Errorf("marshal %s params: %w", method, err),
417			}
418		}
419	
420		req := contract.Request{
421			ID:     id,
422			Method: method,
423			Params: paramsRaw,
424		}
425		payload, err := json.Marshal(req)
426		if err != nil {
427			return nil, &RuntimeError{
428				Class: contract.ErrorClassAdapterPanic,
429				Err:   fmt.Errorf("marshal %s envelope: %w", method, err),
430			}
431		}
432	
433		if err := s.transport.Send(ctx, payload); err != nil {
434			return nil, classifySendError(err)
435		}
436	
437		// Read the matching response. v1 doesn't allow adapter→runtime
438		// requests or notifications outside the initialized notification
439		// (which flows runtime→adapter), so we expect exactly one frame
440		// in response. Interleaved progress notifications are an 8b feature.
441		raw, err := s.transport.Recv(ctx)
442		if err != nil {
443			if errors.Is(err, context.DeadlineExceeded) {
444				return nil, &RuntimeError{
445					Class: contract.ErrorClassAdapterTimeout,
446					Err:   fmt.Errorf("%w: %s exceeded %s", ErrAdapterTimeout, phase, phaseTimeout),
447				}
448			}
449			return nil, classifyTransportError(err)
450		}
451		msg, err := contract.ParseMessage(raw)
452		if err != nil {
453			return nil, &RuntimeError{
454				Class: contract.ErrorClassAdapterPanic,
455				Err:   fmt.Errorf("parse message: %w", err),
456			}
457		}
458		if msg.Kind != contract.MessageKindResponse {
459			return nil, &RuntimeError{
460				Class: contract.ErrorClassAdapterPanic,
461				Err:   fmt.Errorf("%w: got %v while awaiting %s response", ErrAdapterUnexpectedMessage, msg.Kind, method),
462			}
463		}
464		if !msg.HasID || msg.ID.AsInt() != id.AsInt() {
465			return nil, &RuntimeError{
466				Class: contract.ErrorClassAdapterPanic,
467				Err:   fmt.Errorf("%w: response id mismatch (want %d)", ErrAdapterUnexpectedMessage, id.AsInt()),
468			}
469		}
470		_, _ = s.ids.Resolve(msg.ID)
471		if msg.Error != nil {
472			// Class is documented to always be populated. Adapters MAY omit
473			// the optional error_class data field; default to adapter-panic
474			// so callers never see an empty classifier.
475			class := msg.Error.Data.ErrorClass
476			if class == "" {
477				class = contract.ErrorClassAdapterPanic
478			}
479			return nil, &RuntimeError{
480				Class:        class,
481				Err:          fmt.Errorf("adapter returned error %d: %s", msg.Error.Code, msg.Error.Message),
482				AdapterError: msg.Error,
483			}
484		}
485		return &msg, nil
486	}
487	
488	// pathInDeclaredOutputs reports whether opPath is contained within
489	// one of the adapter's declared_outputs. Both sides are normalized
490	// with path.Clean before comparison so an adapter can't smuggle a
491	// path containing ".." or duplicate "/" segments through the gate.
492	//
493	// Returns false for empty paths (warnings exempt themselves at the
494	// caller), absolute paths (declared_outputs are workspace-relative),
495	// paths whose cleaned form starts with ".." (escapes the workspace),
496	// and paths containing a backslash or Windows volume prefix — those
497	// shapes are not absolute under path.IsAbs (which uses the forward-
498	// slash POSIX rules) but are absolute under OS path rules on Windows
499	// and would let an op escape the workspace once interpreted there.
500	func (s *AdapterSession) pathInDeclaredOutputs(opPath string) bool {
501		if opPath == "" {
502			return false
503		}
504		if s.initResult == nil {
505			return false
506		}
507		if path.IsAbs(opPath) {
508			return false
509		}
510		// Windows-safety: path.IsAbs ignores both backslash separators and
511		// drive-letter volume prefixes, so a path like "C:\\foo" or "..\\..\\etc"
512		// would slip past the relative-path gate above. Reject both shapes
513		// outright on every OS — they are never valid for a workspace-relative
514		// path on the wire, regardless of host platform.
515		if strings.ContainsRune(opPath, '\\') {
516			return false
517		}
518		if reWindowsVolumePrefix.MatchString(opPath) {
519			return false
520		}
521		clean := path.Clean(opPath)
522		if clean == ".." || strings.HasPrefix(clean, "../") {
523			return false
524		}
525		for _, decl := range s.initResult.DeclaredOutputs {
526			if decl.Path == "" {
527				continue
528			}
529			declClean := path.Clean(decl.Path)
530			if path.IsAbs(declClean) {
531				continue
532			}
533			// path.Clean turns "" or "./" into ".". A declared output of "."
534			// is the workspace root: every workspace-relative path is contained
535			// within it. Without this case the prefix check below would fail
536			// for any normalized path that doesn't literally start with "./".
537			if declClean == "." {
538				return true
539			}
540			if clean == declClean || strings.HasPrefix(clean, declClean+"/") {
541				return true
542			}
543		}
544		return false
545	}
546	
547	// classifySendError wraps a transport.Send error in a RuntimeError.
548	// Send failures are typically transport-level (process died, pipe
549	// closed); classify as adapter-panic. Free function — does not need
550	// session state.
551	func classifySendError(err error) *RuntimeError {
552		if errors.Is(err, context.DeadlineExceeded) {
553			return &RuntimeError{
554				Class: contract.ErrorClassAdapterTimeout,
555				Err:   fmt.Errorf("%w: send: %s", ErrAdapterTimeout, err.Error()),
556			}
557		}
558		return classifyTransportError(err)
559	}
560	
561	// classifyTransportError wraps a transport-layer error in a
562	// RuntimeError, attaching stderr_tail when available.
563	func classifyTransportError(err error) *RuntimeError {
564		if err == nil {
565			return nil
566		}
567		rt := &RuntimeError{
568			Class: contract.ErrorClassAdapterPanic,
569			Err:   err,
570		}
571		var sxerr *SubprocessExitError
572		if errors.As(err, &sxerr) {
573			rt.ExitCode = sxerr.ExitCode
574			rt.StderrTail = sxerr.StderrTail
575		}
576		return rt
577	}
578	
579	// resolveTimeouts fills zero fields in the supplied timeout struct
580	// from DefaultSubprocessTimeouts. Pure function so it's trivial to
581	// test in isolation.
582	func resolveTimeouts(t SubprocessTimeouts) SubprocessTimeouts {
583		d := DefaultSubprocessTimeouts()
584		if t.Handshake == 0 {
585			t.Handshake = d.Handshake
586		}
587		if t.Emit == 0 {
588			t.Emit = d.Emit
589		}
590		if t.Shutdown == 0 {
591			t.Shutdown = d.Shutdown
592		}
593		return t
594	}
595	
596	// extractCookieFromResult parses the raw initialize result JSON for a
597	// top-level "cookie" field. The contract pins the cookie to a single
598	// canonical location to avoid ambiguity — adapters that echo the
599	// cookie elsewhere fail validation the same way as adapters that omit
600	// it entirely.
601	func extractCookieFromResult(raw json.RawMessage) string {
602		var loose struct {
603			Cookie string `json:"cookie"`
604		}
605		if err := json.Unmarshal(raw, &loose); err != nil {
606			return ""
607		}
608		return loose.Cookie
609	}
610

